sql:
SELECT trip_id, AVG(duration) AS average_duration, rating
FROM trips
GROUP BY trip_id, rating;

SELECT AVG(duration) AS avg_duration
FROM trips
WHERE subscription_type = 'Subscriber';

SELECT COUNT(user_id) AS number_of_vessels, MIN(join_date) AS initial_departure_date
FROM users
WHERE subscription_type = 'Subscriber';

external_knowledge:
- 'voyages' refers to 'trips';
- 'seasoned travelers' refers to users with a 'Subscriber' subscription type;
- 'sea of subscriptions' is a metaphor for the subscription-based service;
- 'harbor of origin' refers to the start station;
- 'destination port' refers to the end station;
- 'vessel' refers to 'bike_id';
- 'path' refers to 'route';
- 'feedback' refers to 'rating' and 'comments';
- 'chart their journey' implies listing all the relevant details of the trip.

sql:
SELECT *
FROM trips
WHERE duration = (SELECT MIN(duration) FROM trips);

SELECT DISTINCT user_id 
FROM trips 
WHERE rating = (SELECT MAX(rating) FROM trips);

SELECT trip_id, duration
FROM trips
ORDER BY duration ASC;
